function normalizeText(value) {
  return String(value ?? '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .trim();
}

function parseMaybeJson(value) {
  if (!value) return {};

  if (typeof value === 'string') {
    try {
      return JSON.parse(value);
    } catch {
      return {};
    }
  }

  if (
    typeof value === 'object' &&
    value.data &&
    typeof value.data === 'string'
  ) {
    try {
      return JSON.parse(value.data);
    } catch {
      return value;
    }
  }

  return value;
}

function extractTags(src) {
  const raw = src?._embedded?.tags ?? src?.tags ?? [];
  const list = Array.isArray(raw) ? raw : (raw ? [raw] : []);
  return list
    .map((t) => normalizeText(t?.name ?? t?.title ?? t?.tag_name ?? t))
    .filter(Boolean);
}

function hashString(input) {
  let hash = 2166136261;
  for (let i = 0; i < input.length; i++) {
    hash ^= input.charCodeAt(i);
    hash = Math.imul(hash, 16777619);
  }
  return (hash >>> 0).toString(16).padStart(8, '0');
}

function unixToIso(value) {
  const n = Number(value);
  if (!Number.isFinite(n) || n <= 0) return null;
  return new Date(n * 1000).toISOString();
}

const event = $items("Normaliza Webhook Payload1")[0].json;
const webhookBody = $items("Kommo Webhook Trigger")[0].json?.body ?? {};

const leadRaw = parseMaybeJson($items("Pega Lead do Kommo")[0].json);
const statusesRaw = parseMaybeJson($items("Pega Pipeline Statuses")[0].json);

const lead = leadRaw?.data && typeof leadRaw.data === 'object' ? leadRaw.data : leadRaw;
const statusesContainer = statusesRaw?.data && typeof statusesRaw.data === 'object' ? statusesRaw.data : statusesRaw;
const statuses = Array.isArray(statusesContainer)
  ? statusesContainer
  : statusesContainer?._embedded?.statuses ?? statusesContainer?.statuses ?? [];

const currentLeadId = Number(lead?.id ?? event.lead_id ?? 0) || null;
const currentPipelineId = Number(lead?.pipeline_id ?? event.pipeline_id ?? 0) || null;
const currentStatusId = Number(lead?.status_id ?? event.status_id ?? 0) || null;

const statusMatch = statuses.find((s) => Number(s?.id ?? s?.status_id ?? 0) === currentStatusId) ?? null;
const currentStageName = statusMatch?.name ?? lead?.status_name ?? event.trigger_stage_name ?? '';

const tags = extractTags(lead);

const closedLike = /vendid|vendido|fechad|perdid|cancelad|arquivad|encerrad/i.test(normalizeText(currentStageName));
const isClosed =
  Boolean(lead?.is_deleted) ||
  Boolean(lead?.closed_at) ||
  closedLike;

const rawMessageId = webhookBody['message[add][0][id]'] ?? null;
const rawMessageCreatedAt = webhookBody['message[add][0][created_at]'] ?? null;
const rawMessageActorName = webhookBody['message[add][0][author][name]'] ?? null;
const rawMessageActorType = webhookBody['message[add][0][author][type]'] ?? null;
const rawMessageText = webhookBody['message[add][0][text]'] ?? null;

const lastMessageId = rawMessageId ? String(rawMessageId) : null;
const lastMessageAt = unixToIso(rawMessageCreatedAt);
const lastMessageActor = rawMessageActorName ?? rawMessageActorType ?? null;
const lastMessageHash = (lastMessageId || lastMessageAt || lastMessageActor || rawMessageText)
  ? hashString([lastMessageId, lastMessageAt, lastMessageActor, rawMessageText].join('|'))
  : null;

return [{
  json: {
    phase: 'before_wait',
    lead_id: currentLeadId,
    lead_name: lead?.name ?? '',
    pipeline_id: currentPipelineId,
    current_status_id: currentStatusId,
    current_stage_name: currentStageName,
    snapshot_last_stage_name: currentStageName,
    snapshot_last_status_id: currentStatusId,
    trigger_status_id: event.status_id ?? null,
    trigger_stage_name: event.trigger_stage_name ?? '',
    event_type: event.event ?? event.event_type ?? 'unknown',
    tags,
    is_closed: isClosed,
    closed_like: closedLike,
    updated_at: lead?.updated_at ?? null,
    pending_lock: null,
    last_message_id: lastMessageId,
    last_message_at: lastMessageAt,
    last_message_actor: lastMessageActor,
    last_message_hash: lastMessageHash,
    lead_full: lead,
    pipeline_statuses: statuses,
    received_at: event.received_at ?? null,
    raw_event: event.raw_event ?? null,
  },
}];

function normalizeText(value) {
  return String(value ?? '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .trim();
}

const state = $items("Constroi Estado de Resgate")[0].json;
const tags = Array.isArray(state.tags) ? state.tags.map(normalizeText) : [];
const stage = normalizeText(state.current_stage_name);
const hasHuman = tags.some((t) => t.includes('atendimento_humano') || t.includes('humano') || t.includes('consultora'));
const hasPending = tags.some((t) => t.includes('resgate_pendente') || t.includes('resgate_em_execucao') || t.includes('resgate_cancelado'));
const closedLike = Boolean(state.is_closed) || /vendid|vendido|fechad|perdid|cancelad|arquivad|encerrad/i.test(stage);

const rules = [
  { key: 'consulta', label: 'consulta', keywords: ['consulta', 'agendamento', 'agenda', 'medica', 'médica'], wait_hours: 24, max_attempts: 2 },
  { key: 'orcamento', label: 'orçamento', keywords: ['orcamento', 'orçamento', 'proposta', 'cotacao', 'cotação', 'valor'], wait_hours: 72, max_attempts: 3 },
  { key: 'crediario', label: 'crediário', keywords: ['crediario', 'crediário', 'parcel', 'document', 'credito', 'crédito'], wait_hours: 48, max_attempts: 2 },
  { key: 'duvidas', label: 'dúvidas', keywords: ['duvida', 'duvidas', 'dúvida', 'dúvidas', 'faq', 'informacao', 'informação'], wait_hours: 24, max_attempts: 2 },
];

const matchedRule = rules.find((rule) => rule.keywords.some((k) => stage.includes(normalizeText(k)))) ?? null;

let should_rescue = false;
let block_reason = null;
let rescue_type = null;
let rescue_label = null;
let wait_hours = 0;
let max_attempts = 1;

if (!state.lead_id) {
  block_reason = 'missing_lead_id';
} else if (closedLike) {
  block_reason = 'closed';
} else if (!stage) {
  block_reason = 'stage_not_available';
} else if (hasHuman) {
  block_reason = 'human_handling';
} else if (hasPending) {
  block_reason = 'already_pending_or_running';
} else if (!matchedRule) {
  block_reason = 'stage_not_eligible';
} else {
  should_rescue = true;
  rescue_type = matchedRule.key;
  rescue_label = matchedRule.label;
  wait_hours = matchedRule.wait_hours;
  max_attempts = matchedRule.max_attempts;
}

return [{
  json: {
    ...state,
    should_rescue,
    block_reason,
    rescue_type,
    rescue_label,
    wait_hours,
    max_attempts,
    matched_rule: matchedRule,
  },
}];

function normalizeText(value) {
  return String(value ?? '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .trim();
}

function sqlText(value) {
  if (value === null || value === undefined || value === '') return 'NULL';
  return `'${String(value).replace(/'/g, "''")}'`;
}

function sqlNumber(value) {
  const n = Number(value);
  return Number.isFinite(n) ? String(n) : 'NULL';
}

function toIso(value) {
  if (!value) return null;
  const d = new Date(value);
  return Number.isFinite(d.getTime()) ? d.toISOString() : null;
}

const state = $json;

const leadId = Number(state.lead_id);
const pipelineId = Number(state.pipeline_id);
const statusId = Number(state.current_status_id);

if (!Number.isFinite(leadId)) {
  throw new Error('lead_id inválido no Compoe Fila de Resgate');
}

const rescueType = normalizeText(state.rescue_type || 'general')
  .replace(/[^a-z0-9]+/g, '_')
  .replace(/^_|_$/g, '') || 'general';

const rescueTypeUpper = rescueType.toUpperCase();
const waitHours = Math.max(1, Number(state.wait_hours || 1));
const maxAttempts = Math.max(1, Number(state.max_attempts || 1));

const queueKey = `${leadId}:${rescueType}:${Number.isFinite(statusId) ? statusId : 'null'}`;

const executeAtDate = new Date(Date.now() + waitHours * 60 * 60 * 1000);
const lastMessageAtDate = state.last_message_at ? new Date(state.last_message_at) : null;

const minMessageWindowDate = lastMessageAtDate
  ? new Date(lastMessageAtDate.getTime() + 72 * 60 * 60 * 1000)
  : executeAtDate;

const notBeforeAtDate = new Date(
  Math.max(executeAtDate.getTime(), minMessageWindowDate.getTime())
);

const executeAt = executeAtDate.toISOString();
const notBeforeAt = notBeforeAtDate.toISOString();

const patchBody = {
  updated_by: 0,
  tags_to_add: [
    { name: 'RESGATE_PENDENTE' },
    { name: `RESGATE_PENDENTE_${rescueTypeUpper}` },
  ],
  tags_to_delete: [],
};

const sqlUpsertQueue = `
INSERT INTO public.rescue_queue (
  queue_key,
  lead_id,
  pipeline_id,
  status_id,
  rescue_type,
  rescue_label,
  wait_hours,
  max_attempts,
  attempt,
  execute_at,
  not_before_at,
  status,
  block_reason,
  last_event_type,
  last_stage_name,
  snapshot_last_stage_name,
  last_message_id,
  last_message_at,
  last_message_actor,
  last_message_hash,
  created_at,
  updated_at
) VALUES (
  ${sqlText(queueKey)},
  ${sqlNumber(leadId)},
  ${sqlNumber(pipelineId)},
  ${sqlNumber(statusId)},
  ${sqlText(rescueType)},
  ${sqlText(state.rescue_label || rescueType)},
  ${sqlNumber(waitHours)},
  ${sqlNumber(maxAttempts)},
  0,
  ${sqlText(executeAt)}::timestamptz,
  ${sqlText(notBeforeAt)}::timestamptz,
  'pending',
  NULL,
  ${sqlText(state.event_type || 'unknown')},
  ${sqlText(state.current_stage_name || '')},
  ${sqlText(state.snapshot_last_stage_name || state.current_stage_name || '')},
  ${sqlText(state.last_message_id)},
  ${state.last_message_at ? `${sqlText(state.last_message_at)}::timestamptz` : 'NULL'},
  ${sqlText(state.last_message_actor)},
  ${sqlText(state.last_message_hash)},
  NOW(),
  NOW()
)
ON CONFLICT (queue_key) DO UPDATE SET
  lead_id = EXCLUDED.lead_id,
  pipeline_id = EXCLUDED.pipeline_id,
  status_id = EXCLUDED.status_id,
  rescue_type = EXCLUDED.rescue_type,
  rescue_label = EXCLUDED.rescue_label,
  wait_hours = EXCLUDED.wait_hours,
  max_attempts = EXCLUDED.max_attempts,
  attempt = EXCLUDED.attempt,
  execute_at = EXCLUDED.execute_at,
  not_before_at = EXCLUDED.not_before_at,
  status = EXCLUDED.status,
  block_reason = EXCLUDED.block_reason,
  last_event_type = EXCLUDED.last_event_type,
  last_stage_name = EXCLUDED.last_stage_name,
  snapshot_last_stage_name = EXCLUDED.snapshot_last_stage_name,
  last_message_id = EXCLUDED.last_message_id,
  last_message_at = EXCLUDED.last_message_at,
  last_message_actor = EXCLUDED.last_message_actor,
  last_message_hash = EXCLUDED.last_message_hash,
  updated_at = NOW();
`.trim();

const sqlInsertHistoryQueued = `
INSERT INTO public.rescue_history (
  queue_key,
  lead_id,
  attempt,
  action,
  result,
  details,
  created_at
) VALUES (
  ${sqlText(queueKey)},
  ${sqlNumber(leadId)},
  0,
  'queued',
  'pending',
  ${sqlText(
    `agendado_para=${executeAt} | not_before_at=${notBeforeAt} | wait_hours=${waitHours} | rescue_type=${rescueType} | last_message_at=${state.last_message_at || 'null'} | last_message_actor=${state.last_message_actor || 'null'}`
  )},
  NOW()
);
`.trim();

return [{
  json: {
    ...state,
    queue_key: queueKey,
    attempt: 0,
    execute_at: executeAt,
    not_before_at: notBeforeAt,
    status: 'pending',
    patch_body: patchBody,
    sql_upsert_queue: sqlUpsertQueue,
    sql_insert_history_queued: sqlInsertHistoryQueued,
  },
}];

function sqlText(value) {
  if (value === null || value === undefined) return 'NULL';
  return `'${String(value).replace(/'/g, "''")}'`;
}

const state = $json;
const queueKey = `${state.lead_id || 'unknown'}:${state.rescue_type || 'general'}:${state.current_status_id || 'na'}`;

const sqlInsertHistorySkipped = `
INSERT INTO public.rescue_history (
  queue_key, lead_id, attempt, action, result, details, created_at
) VALUES (
  ${sqlText(queueKey)},
  ${state.lead_id === null || state.lead_id === undefined ? '0' : Number(state.lead_id)},
  0,
  'skip',
  'blocked',
  ${sqlText(state.block_reason || 'not_eligible')},
  NOW()
);
`.trim();

return [{
  json: {
    ...state,
    queue_key: queueKey,
    sql_insert_history_skipped: sqlInsertHistorySkipped,
  },
}];

const body = $input.first().json.body ?? {};

const get = (key) => {
  const value = body[key];
  return value === undefined || value === null || value === '' ? null : value;
};

const toNumber = (value) => {
  const n = Number(value);
  return Number.isFinite(n) ? n : null;
};

let output = {
  event: null,
  lead_id: null,
  contact_id: null,
  pipeline_id: null,
  status_id: null,
  old_status_id: null,
  raw_event: null,
};

if (get('message[add][0][entity_id]') !== null) {
  output.event = 'message';
  output.raw_event = 'message[add]';
  output.lead_id = toNumber(get('message[add][0][entity_id]'));
  output.contact_id = toNumber(get('message[add][0][contact_id]'));
}
else if (get('leads[status][0][id]') !== null) {
  output.event = 'lead_status';
  output.raw_event = 'leads[status]';
  output.lead_id = toNumber(get('leads[status][0][id]'));
  output.pipeline_id = toNumber(get('leads[status][0][pipeline_id]'));
  output.status_id = toNumber(get('leads[status][0][status_id]'));
  output.old_status_id = toNumber(get('leads[status][0][old_status_id]'));
}
else if (get('leads[add][0][id]') !== null) {
  output.event = 'lead_add';
  output.raw_event = 'leads[add]';
  output.lead_id = toNumber(get('leads[add][0][id]'));
  output.pipeline_id = toNumber(get('leads[add][0][pipeline_id]'));
  output.status_id = toNumber(get('leads[add][0][status_id]'));
}
else if (get('leads[update][0][id]') !== null) {
  output.event = 'lead_update';
  output.raw_event = 'leads[update]';
  output.lead_id = toNumber(get('leads[update][0][id]'));
  output.pipeline_id = toNumber(get('leads[update][0][pipeline_id]'));
  output.status_id = toNumber(get('leads[update][0][status_id]'));
}
else if (get('contacts[add][0][id]') !== null) {
  output.event = 'contact_add';
  output.raw_event = 'contacts[add]';
  output.contact_id = toNumber(get('contacts[add][0][id]'));
}
else if (get('contacts[update][0][id]') !== null) {
  output.event = 'contact_update';
  output.raw_event = 'contacts[update]';
  output.contact_id = toNumber(get('contacts[update][0][id]'));
}

return [{ json: output }];
